The router implements staleness detection to prevent serving outdated cached routes:

```javascript
// Fresh score for "keystone" = 85
// Cached agent = "lantern", cached score = 60
// Staleness detected if: fresh_score > cached_score * 0.8
// 85 > 60 * 0.8 (85 > 48) → STALE, use fresh routing

source: "cache_stale"
```

**Rules:**
- Cache only returned if confidence > 0.7
- Cached agent must match fresh scores (within 20% tolerance)
- Staleness triggers fresh scoring + cache update

The convergence router is used by Dream Chat to classify user intents before selecting a system prompt:

```javascript
const router = getRouter();
const routing = await router.routeIntent(userMessage);
const systemPrompt = AGENT_PERSONAS[routing.agent];
const tokensSaved = routing.cacheHit ? 15 : 0;
```

```javascript
// convergence-router.js
function classifyIntent(message) {
  const patterns = {
    market_search: /market|price|trading|kalshi/i,
    code_gen: /code|script|function|implement/i,
    debug: /error|bug|fix|troubleshoot/i,
    docs: /api|endpoint|documentation/i,
    trading: /order|buy|sell|position/i
  };

  for (const [intent, pattern] of Object.entries(patterns)) {
    if (pattern.test(message)) return intent;
  }
  return 'default';
}
```

```javascript
function selectRoute(intent, message) {
  const routes = {
    market_search: 'market-search',
    code_gen: 'code-gen',
    debug: 'debug-troubleshoot',
    docs: 'docs-api',
    trading: 'trading-order',
    default: 'keystone-general'
  };

  return routes[intent] || routes.default;
}
```

```javascript
function checkCache(route, message) {
  const cacheKey = generateCacheKey(route, message);
  const cached = patternCache.get(cacheKey);

  if (cached && isCacheValid(cached)) {
    return cached.response;
  }
  return null;
}
```

```javascript
function selectProvider(route, complexity) {
  const providerChain = getProviderChain();

  if (complexity === 'low') {
    return providerChain.cheap; // Gemini, Ollama
  } else if (complexity === 'high') {
    return providerChain.premium; // Claude, OpenAI
  }

  return providerChain.balanced;
}
```

